tlFloat2ChannelChunk::tlFloat2ChannelChunk(tlReadChunk16* ch)
{
    assert(ch->GetID() == Pure3D::Animation::ChannelData::FLOAT_2);
    ident = Pure3D::Animation::ChannelData::FLOAT_2;

    tlFile* f = ch->GetFile();
    unsigned int i;

    version = f->GetLong();
    param = f->GetLong();
    numframes = f->GetLong();
    frames = new unsigned short[numframes];
    for(i = 0; i < numframes; i++)
    {
        frames[i] = f->GetWord();
    }
    values = new tlPoint2D[numframes];
    for(i = 0; i < numframes; i++)
    {
        values[i].Read(f);
    }
    while (!ch->EndOfChunk())
    {
        AppendSubChunk(LoadSubChunk(f));
    }
    if(sortPriority == -1)
    {
        sortPriority = FindPriority(Pure3D::Animation::ChannelData::FLOAT_2);
    }
}

