tlVector1DOFChannelChunk::~tlVector1DOFChannelChunk()
{

    if(frames != NULL){
        delete[] frames;
    }
    if(values != NULL){
        delete[] values;
    }
}

tlVector1DOFChannelChunk::tlVector1DOFChannelChunk(tlReadChunk16* ch)
{
    assert(ch->GetID() == Pure3D::Animation::ChannelData::VECTOR_1DOF);
    ident = Pure3D::Animation::ChannelData::VECTOR_1DOF;

    tlFile* f = ch->GetFile();
    unsigned int i;

    version = f->GetLong();
    param = f->GetLong();
    mapping = f->GetWord();
    constants.Read(f);
    numframes = f->GetLong();
    frames = new unsigned short[numframes];
    for(i = 0; i < numframes; i++)
    {
        frames[i] = f->GetWord();
    }
    values = new float[numframes];
    for(i = 0; i < numframes; i++)
    {
        values[i] = f->GetFloat();
    }
    while (!ch->EndOfChunk())
    {
        AppendSubChunk(LoadSubChunk(f));
    }
    if(sortPriority == -1)
    {
        sortPriority = FindPriority(Pure3D::Animation::ChannelData::VECTOR_1DOF);
    }
}

