tlVector1DOFChannelChunk::Init()
{
    ident = Pure3D::Animation::ChannelData::VECTOR_1DOF;
    version = 0;
    param = 0;
    mapping = 0;
    constants.Init( );
    numframes = 0;
    frames = NULL;
    values = NULL;
               
    if(sortPriority == -1)
    {
        sortPriority = FindPriority(Pure3D::Animation::ChannelData::VECTOR_1DOF);
    }
}

long 
tlVector1DOFChannelChunk::Size( )
{

    long s = 2*sizeof( long );

    int i;

    s += sizeof( version );
    s += sizeof( param );
    s += sizeof( mapping );
    s += sizeof( constants );
    s += sizeof( numframes );
    for(i = 0; i < (int)numframes; i++)
    {
        s += sizeof( frames[i ] );
    }
    for(i = 0; i < (int)numframes; i++)
    {
        s += sizeof( values[i ] );
    }
    for( i=0; i < SubChunkCount( ); i++){
        s += GetSubChunk(i)->Size();
    }

    return s;
}

tlVector1DOFChannelChunk&
tlVector1DOFChannelChunk::operator=(const tlVector1DOFChannelChunk& a)
{
    unsigned int i;

    if(ident != a.ident)
    {
        assert(ident != a.ident);
        return *this;
    }

    version = a.version;
    param = a.param;
    mapping = a.mapping;
    constants = a.constants;
    numframes = a.numframes;
    if(frames)
    {
        delete frames;
    }
    frames = new unsigned short[numframes];
    for( i = 0; i < numframes ; i++ )
    {
        frames[i] = a.frames[i];
    }
    if(values)
    {
        delete values;
    }
    values = new float[numframes];
    for( i = 0; i < numframes ; i++ )
    {
        values[i] = a.values[i];
    }

    int subch;

    for(subch = 0; subch < subcount; subch++)
    {
        RemoveSubChunk(subch);
    }

    for(subch = 0; subch < a.subcount; subch++)
    {
        AppendSubChunk(a.GetSubChunk(subch)->Copy());
    }
    
    return *this;
}

bool
tlVector1DOFChannelChunk::operator==(const tlDataChunk& a)
{
    unsigned int i;

    const tlVector1DOFChannelChunk* aptr = dynamic_cast<const tlVector1DOFChannelChunk*>(&a);

    if(aptr == NULL)
    {
        return false;
    }

    if(ident != aptr->ident)
    {
        return false;
    }


    if(!(version == aptr->version))
    {
        return false;
    }
    if(!(param == aptr->param))
    {
        return false;
    }
    if(!(mapping == aptr->mapping))
    {
        return false;
    }
    if(!(constants == aptr->constants))
    {
        return false;
    }
    if(!(numframes == aptr->numframes))
    {
        return false;
    }
    for(i = 0; i < numframes; i++)
    {
        if(!(frames[i] == aptr->frames[i]))
        {
            return false;
        }
    }
    for(i = 0; i < numframes; i++)
    {
        if(!(values[i] == aptr->values[i]))
        {
            return false;
        }
    }

    // check the subchunks
    if(subcount != aptr->subcount)
    {
        return false;
    }

    for(int subch = 0; subch < subcount; subch++)
    {
        if(!((*GetSubChunk(subch)) == (*aptr->GetSubChunk(subch))))
        {
            return false;
        }
    }
    return true;
}

