void
tlVector1DOFChannelChunk::Write(tlFile* f)
{
    tlWriteChunk16 ch(f, ident);

    unsigned int i;
        f->PutLong(version);
        f->PutLong(param);
        f->PutWord(mapping);
        constants.Write(f);
        f->PutLong(numframes);
    for(i = 0; i < numframes ; i++)
    {
        f->PutWord(frames[i]);
    }
    for(i = 0; i < numframes ; i++)
    {
        f->PutFloat(values[i]);
    }

    ch.ContentFinish();
    for(int subch = 0; subch < subcount; subch++)
    {
        GetSubChunk(subch)->Write(f);
    }
}

void
tlVector1DOFChannelChunk::Print(int indent, unsigned int printdepth, unsigned int typemask)
{
    unsigned int i;

    if ( printdepth == 0 )
    {
        return;
    }

    printf("%*stlVector1DOFChannelChunk (%4x)\n",indent,"",(int) ident);
    printf("%*s  Version   = %ld\n",indent,"",version);
    printf("%*s  Param     = %08lx\n",indent,"",param);
    printf("%*s  Mapping   = %d\n",indent,"",mapping);
    printf("%*s  Constants:\n",indent,"");
    constants.Print(0, indent+4);
    printf("%*s  NumFrames = %ld\n",indent,"",numframes);
    printf("%*s  Frames:\n",indent,"");
    for( i=0; i < numframes; i++)
    {
         printf("%*s    %d %d\n",indent,"",i,frames[i]);
    }
    printf("%*s  Values:\n",indent,"");
    for( i=0; i < numframes; i++)
    {
         printf("%*s    %d %f\n",indent,"",i,values[i]);
    }

    if(subcount)
    {
        printf("%*s  SubChunks (%d):\n",indent,"",subcount);
        for(int subch = 0; subch < subcount; subch++)
        {
            GetSubChunk(subch)->Print(indent+4, printdepth-1, typemask);
        }
    }
}

void
tlVector1DOFChannelChunk::PrintFormatted(int indent)
{
    unsigned int i;
    printf("%*schunk 0x%04x  \n",indent,"",(int) ident);
    printf("%*s  int   %12ld # Version  \n",indent,"",version);
    printf("%*s  int   0x%08lx # Param    \n",indent,"",param);
    printf("%*s  short %12d # Mapping  \n",indent,"",mapping);
    printf("%*s  # Constants:\n",indent,"");
    constants.PrintFormatted(0, indent+4);
    printf("%*s  int   %12ld # NumFrames\n",indent,"",numframes);
    printf("%*s  repeat 1 short # Frames   \n",indent,"");
    for( i=0; i < numframes; i++)
    {
         printf("%*s    %12d\n",indent,"",frames[i]);
    }
    printf("%*s  endrepeat\n",indent,"");
    printf("%*s  repeat 1 float # Values   \n",indent,"");
    for( i=0; i < numframes; i++)
    {
         printf("%*s    %12f\n",indent,"",values[i]);
    }
    printf("%*s  endrepeat\n",indent,"");
    if(subcount)
    {
        for(int i=0;i<subcount;i++)
        {
            GetSubChunk(i)->PrintFormatted(indent+2);
        }
    }
    printf("%*sendchunk\n",indent,"");
}

