tlVector2DOFChannelChunk::operator==(const tlDataChunk& a)
{
    unsigned int i;

    const tlVector2DOFChannelChunk* aptr = dynamic_cast<const tlVector2DOFChannelChunk*>(&a);

    if(aptr == NULL)
    {
        return false;
    }

    if(ident != aptr->ident)
    {
        return false;
    }


    if(!(version == aptr->version))
    {
        return false;
    }
    if(!(param == aptr->param))
    {
        return false;
    }
    if(!(mapping == aptr->mapping))
    {
        return false;
    }
    if(!(constants == aptr->constants))
    {
        return false;
    }
    if(!(numframes == aptr->numframes))
    {
        return false;
    }
    for(i = 0; i < numframes; i++)
    {
        if(!(frames[i] == aptr->frames[i]))
        {
            return false;
        }
    }
    for(i = 0; i < numframes; i++)
    {
        if(!(values[i] == aptr->values[i]))
        {
            return false;
        }
    }

    // check the subchunks
    if(subcount != aptr->subcount)
    {
        return false;
    }

    for(int subch = 0; subch < subcount; subch++)
    {
        if(!((*GetSubChunk(subch)) == (*aptr->GetSubChunk(subch))))
        {
            return false;
        }
    }
    return true;
}

