void
tlVector2DOFChannelChunk::Write(tlFile* f)
{
    tlWriteChunk16 ch(f, ident);

    unsigned int i;
        f->PutLong(version);
        f->PutLong(param);
        f->PutWord(mapping);
        constants.Write(f);
        f->PutLong(numframes);
    for(i = 0; i < numframes ; i++)
    {
        f->PutWord(frames[i]);
    }
    for(i = 0; i < numframes ; i++)
    {
        values[i].Write(f);
    }

    ch.ContentFinish();
    for(int subch = 0; subch < subcount; subch++)
    {
        GetSubChunk(subch)->Write(f);
    }
}

