// tlVector3DOFChannelChunk

int tlVector3DOFChannelChunk::sortPriority = -1;

tlVector3DOFChannelChunk::tlVector3DOFChannelChunk()
{
    Init();
}

tlVector3DOFChannelChunk::tlVector3DOFChannelChunk(const tlVector3DOFChannelChunk& ch)
{
    Init();
    *this = ch;
}

tlVector3DOFChannelChunk::~tlVector3DOFChannelChunk()
{

    if(frames != NULL){
        delete[] frames;
    }
    if(values != NULL){
        delete[] values;
    }
}

tlVector3DOFChannelChunk::tlVector3DOFChannelChunk(tlReadChunk16* ch)
{
    assert(ch->GetID() == Pure3D::Animation::ChannelData::VECTOR_3DOF);
    ident = Pure3D::Animation::ChannelData::VECTOR_3DOF;

    tlFile* f = ch->GetFile();
    unsigned int i;

    version = f->GetLong();
    param = f->GetLong();
    numframes = f->GetLong();
    frames = new unsigned short[numframes];
    for(i = 0; i < numframes; i++)
    {
        frames[i] = f->GetWord();
    }
    values = new tlPoint[numframes];
    for(i = 0; i < numframes; i++)
    {
        values[i].Read(f);
    }
    while (!ch->EndOfChunk())
    {
        AppendSubChunk(LoadSubChunk(f));
    }
    if(sortPriority == -1)
    {
        sortPriority = FindPriority(Pure3D::Animation::ChannelData::VECTOR_3DOF);
    }
}

void
tlVector3DOFChannelChunk::Init()
{
    ident = Pure3D::Animation::ChannelData::VECTOR_3DOF;
    version = 0;
    param = 0;
    numframes = 0;
    frames = NULL;
    values = NULL;
               
    if(sortPriority == -1)
    {
        sortPriority = FindPriority(Pure3D::Animation::ChannelData::VECTOR_3DOF);
    }
}

long 
tlVector3DOFChannelChunk::Size( )
{

    long s = 2*sizeof( long );

    int i;

    s += sizeof( version );
    s += sizeof( param );
    s += sizeof( numframes );
    for(i = 0; i < (int)numframes; i++)
    {
        s += sizeof( frames[i ] );
    }
    for(i = 0; i < (int)numframes; i++)
    {
        s += sizeof( values[i ] );
    }
    for( i=0; i < SubChunkCount( ); i++){
        s += GetSubChunk(i)->Size();
    }

    return s;
}

tlVector3DOFChannelChunk&
tlVector3DOFChannelChunk::operator=(const tlVector3DOFChannelChunk& a)
{
    unsigned int i;

    if(ident != a.ident)
    {
        assert(ident != a.ident);
        return *this;
    }

    version = a.version;
    param = a.param;
    numframes = a.numframes;
    if(frames)
    {
        delete frames;
    }
    frames = new unsigned short[numframes];
    for( i = 0; i < numframes ; i++ )
    {
        frames[i] = a.frames[i];
    }
    if(values)
    {
        delete values;
    }
    values = new tlPoint[numframes];
    for( i = 0; i < numframes ; i++ )
    {
        values[i] = a.values[i];
    }

    int subch;

    for(subch = 0; subch < subcount; subch++)
    {
        RemoveSubChunk(subch);
    }

    for(subch = 0; subch < a.subcount; subch++)
    {
        AppendSubChunk(a.GetSubChunk(subch)->Copy());
    }
    
    return *this;
}

