bool 
tlCompressedQuaternionChannelChunk::SetFieldValue(int fieldIndex, const char* new_val)
{
    switch(fieldIndex)
    {
        case 0:
        {
            char* end_ptr;
            unsigned long tmp;
            tmp = (unsigned long)strtoul(new_val, &end_ptr, 0);
            if (*end_ptr == 0)
            {
                version = tmp;
                return true;
            }
            return false;
        }
        case 1:
        {
            param = (unsigned long) tlFourCC(new_val);
            return true;
        }
        case 2:
        {
            char* end_ptr;
            unsigned long tmp;
            tmp = (unsigned long)strtoul(new_val, &end_ptr, 0);
            if (*end_ptr == 0)
            {
                numframes = tmp;
                return true;
            }
            return false;
        }
        case 3:
            return false;
        case 4:
            return false;
        default:
            return false;
    }
}

