tlCompressedQuaternionChannelChunk::SetFieldArrayValue(int fieldIndex, int arrayIndex, const char* new_val)
{
    switch(fieldIndex)
    {
        case 0:
            return false;

        case 1:
            return false;

        case 2:
            return false;

        case 3:
        {
            char* end_ptr;
            unsigned short tmp;
            tmp = (unsigned short)strtol(new_val, &end_ptr, 0);
            if (*end_ptr == 0)
            {
                frames[arrayIndex] = tmp;
                return true;
            }
            return false;
        }

        case 4:
            return values[arrayIndex].SetFieldValue(new_val);

        default:
            return false;
    }
}

