tlStringChannelChunk::Init()
{
    ident = Pure3D::Animation::ChannelData::STRING;
    version = 0;
    param = 0;
    numframes = 0;
    frames = NULL;
    values = NULL;
               
    if(sortPriority == -1)
    {
        sortPriority = FindPriority(Pure3D::Animation::ChannelData::STRING);
    }
}

