int tlColourChannelChunk::sortPriority = -1;

tlColourChannelChunk::tlColourChannelChunk()
{
    Init();
}

tlColourChannelChunk::tlColourChannelChunk(const tlColourChannelChunk& ch)
{
    Init();
    *this = ch;
}

tlColourChannelChunk::~tlColourChannelChunk()
{

    if(frames != NULL){
        delete[] frames;
    }
    if(values != NULL){
        delete[] values;
    }
}

tlColourChannelChunk::tlColourChannelChunk(tlReadChunk16* ch)
{
    assert(ch->GetID() == Pure3D::Animation::ChannelData::COLOUR);
    ident = Pure3D::Animation::ChannelData::COLOUR;

    tlFile* f = ch->GetFile();
    unsigned int i;

    version = f->GetLong();
    param = f->GetLong();
    numframes = f->GetLong();
    frames = new unsigned short[numframes];
    for(i = 0; i < numframes; i++)
    {
        frames[i] = f->GetWord();
    }
    values = new unsigned long[numframes];
    for(i = 0; i < numframes; i++)
    {
        values[i] = f->GetLong();
    }
    while (!ch->EndOfChunk())
    {
        AppendSubChunk(LoadSubChunk(f));
    }
    if(sortPriority == -1)
    {
        sortPriority = FindPriority(Pure3D::Animation::ChannelData::COLOUR);
    }
}

void
tlColourChannelChunk::Init()
{
    ident = Pure3D::Animation::ChannelData::COLOUR;
    version = 0;
    param = 0;
    numframes = 0;
    frames = NULL;
    values = NULL;
               
    if(sortPriority == -1)
    {
        sortPriority = FindPriority(Pure3D::Animation::ChannelData::COLOUR);
    }
}

long 
tlColourChannelChunk::Size( )
{

    long s = 2*sizeof( long );

    int i;

    s += sizeof( version );
    s += sizeof( param );
    s += sizeof( numframes );
    for(i = 0; i < (int)numframes; i++)
    {
        s += sizeof( frames[i ] );
    }
    for(i = 0; i < (int)numframes; i++)
    {
        s += sizeof( values[i ] );
    }
    for( i=0; i < SubChunkCount( ); i++){
        s += GetSubChunk(i)->Size();
    }

    return s;
}

tlColourChannelChunk&
tlColourChannelChunk::operator=(const tlColourChannelChunk& a)
{
    unsigned int i;

    if(ident != a.ident)
    {
        assert(ident != a.ident);
        return *this;
    }

    version = a.version;
    param = a.param;
    numframes = a.numframes;
    if(frames)
    {
        delete frames;
    }
    frames = new unsigned short[numframes];
    for( i = 0; i < numframes ; i++ )
    {
        frames[i] = a.frames[i];
    }
    if(values)
    {
        delete values;
    }
    values = new unsigned long[numframes];
    for( i = 0; i < numframes ; i++ )
    {
        values[i] = a.values[i];
    }

    int subch;

    for(subch = 0; subch < subcount; subch++)
    {
        RemoveSubChunk(subch);
    }

    for(subch = 0; subch < a.subcount; subch++)
    {
        AppendSubChunk(a.GetSubChunk(subch)->Copy());
    }
    
    return *this;
}

